const items = $input.all();
const target = $('Smart Command Router').first().json.target || 'all';
const chatId = $('Smart Command Router').first().json.chatId;
let message = '';

if (target === 'all') {
  if (items.length === 0) {
    message = '📋 *Email Status*\n\nNo emails found in the sheet.';
  } else {
    const rows = items.map(i => `📧 ${i.json.Email} → *${i.json.status || 'N/A'}*`);
    message = `📋 *All Email Statuses (${items.length} total)*\n\n${rows.join('\n')}`;
  }
} else {
  const found = items.find(i => i.json.Email === target);
  if (found) {
    message = `📧 *Status for ${target}*\n\nStatus: *${found.json.status || 'N/A'}*\nSent At: ${found.json.sentAt || 'N/A'}\nAccount Used: ${found.json.AccountUsed || 'N/A'}`;
  } else {
    message = `❌ Email not found: ${target}`;
  }
}

return [{ json: { message, chatId } }];

const items = $input.all();
const target = $('Smart Command Router').first().json.target || 'all';
const chatId = $('Smart Command Router').first().json.chatId;
const results = [];

for (const item of items) {
  const row = item.json;
  let shouldReset = false;
  if (target === 'all') shouldReset = true;
  else if (target === 'all_failed' && row.status === 'Failed') shouldReset = true;
  else if (row.Email === target) shouldReset = true;
  if (shouldReset) {
    results.push({ json: { Email: row.Email, status: 'pending', sentAt: '', AccountUsed: '', chatId } });
  }
}

if (results.length === 0) {
  results.push({ json: { Email: '_none_', status: 'pending', sentAt: '', AccountUsed: '', chatId, noMatch: true } });
}

return results;

