const items = $input.all();
let sent = 0, failed = 0, pending = 0;
for (const item of items) {
  const s = (item.json.status || '').toLowerCase();
  if (s === 'sent') sent++;
  else if (s === 'failed') failed++;
  else if (s === 'pending') pending++;
}
const total = items.length;
const successRate = (sent + failed) > 0 ? ((sent / (sent + failed)) * 100).toFixed(1) + '%' : 'N/A';
return [{
  json: {
    message: `📊 *Campaign Stats*\n\n📧 Total Emails: ${total}\n✅ Sent: ${sent}\n❌ Failed: ${failed}\n⏳ Pending: ${pending}\n📈 Success Rate: ${successRate}`,
    chatId: $('Smart Command Router').first().json.chatId
  }
}];

const items = $input.all();
const lines = items.map((i, idx) => `${idx + 1}. ${i.json.Email} — *${i.json.status || 'N/A'}*`);
const message = `📋 *Email List (${items.length} total)*\n\n${lines.join('\n')}`;
return [{ json: { message, chatId: $('Smart Command Router').first().json.chatId } }];

const sheetRows = $input.all();
const routerData = $('Smart Command Router').first().json;
let newEmails = [...(routerData.emails || [])];
if (newEmails.length === 0 && routerData.email) {
  newEmails.push(routerData.email);
}
const chatId = routerData.chatId;
const existingSet = new Set();
if (sheetRows[0] && sheetRows[0].json && sheetRows[0].json.Email !== undefined) {
  for (const i of sheetRows) {
    const email = (i.json.Email || i.json.email || '').toString().toLowerCase().trim();
    if (email) existingSet.add(email);
  }
}
const toAdd = [];
const skipped = [];
for (const email of newEmails) {
  const norm = email.toLowerCase().trim();
  if (!norm || !norm.includes('@')) continue;
  if (existingSet.has(norm)) {
    skipped.push(email);
  } else {
    toAdd.push(email);
    existingSet.add(norm);
  }
}
return [{ json: { toAdd, skipped, chatId, hasNew: toAdd.length > 0 } }];

