const sheetRows = $input.all();
const routerData = $('Smart Command Router').first().json;
let emailsToRemove = [...(routerData.emails || [])];
if (emailsToRemove.length === 0 && routerData.email) {
  emailsToRemove.push(routerData.email);
}
const chatId = routerData.chatId;
const toRemove = [];
const notFound = [];
if (!sheetRows[0] || !sheetRows[0].json || sheetRows[0].json.Email === undefined) {
  return [{ json: { toRemove: [], notFound: emailsToRemove, chatId, hasMatches: false, removedEmails: [] } }];
}
for (const emailRaw of emailsToRemove) {
  const norm = emailRaw.toLowerCase().trim();
  const match = sheetRows.find(
    row => (row.json.Email || row.json.email || '').toString().toLowerCase().trim() === norm
  );
  if (match) {
    toRemove.push({ exactEmail: match.json.Email, row_number: match.json.row_number });
  } else {
    notFound.push(emailRaw);
  }
}
toRemove.sort((a, b) => b.row_number - a.row_number);
return [{ json: { toRemove, notFound, chatId, hasMatches: toRemove.length > 0, removedEmails: toRemove.map(r => r.exactEmail) } }];

const data = $input.first().json;
const toRemove = data.toRemove || [];
const notFound = data.notFound || [];
const chatId = data.chatId;
const removedEmails = data.removedEmails || [];

return toRemove.map(r => ({
  json: {
    exactEmail: r.exactEmail,
    row_number: r.row_number,
    notFound,
    removedEmails,
    chatId
  }
}));

